import React from 'react';

function App() {
  return (
    <div className="App">
      <header>
        <h1>Welcome to My React App!</h1>
      </header>
      <main>
        <p>This is the main content of the app.</p>
      </main>
      <footer>
        <p>© 2021 React Project. All rights reserved.</p>
      </footer>
    </div>
  );
